We support the above-requested behaviour on all platforms using `TextEditingController` and `FocusNode`. I have mentioned a sample code below. 

However, it seems we do NOT support `SelectAllOnFocus` property feature by default. I have verified it on all platforms excluding Windows.

The expectation is to enable this behaviour by toggling a single property on `TextField` object, right ?

### Sample Code
In the following example, we have two `TextField`s. The last `TextField`, supports `SelectAllOnFocus` feature.
```dart
class _MyHomePageState extends State<MyHomePage> {
  int _counter = 0;
  String inputText = "";
  late TextEditingController _controller;
  late FocusNode _focusNode;

  @override
  void initState() {
    super.initState();
    _controller = TextEditingController(text: "This text will be selected on focus");
    _focusNode = FocusNode();

    // Add a listener to handle focus changes
    _focusNode.addListener(() {
      if (_focusNode.hasFocus) {
        _controller.selection = TextSelection(
          baseOffset: 0,
          extentOffset: _controller.text.length,
        );
      }
    });
  }

  void _incrementCounter() {
    setState(() {
      _counter++;
    });
  }

  @override
  void dispose() {
    _controller.dispose();
    _focusNode.dispose();
    super.dispose();
  }


  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: Text(widget.title),
      ),
      body: Center(
        child: Column(
          mainAxisAlignment: MainAxisAlignment.center,
          children: <Widget>[
            const Text('You have pushed the button this many times:'),
            Text(
              '$_counter',
              style: Theme.of(context).textTheme.headlineMedium,
            ),
            TextField(
              onChanged: (value) {
                setState(() {
                  inputText = value;
                });
              },
              decoration: InputDecoration(
                labelText: "Enter something",
                border: OutlineInputBorder(),
              ),
            ),
            TextField(
              controller: _controller,
              focusNode: _focusNode,
              onChanged: (value) {
                setState(() {
                  inputText = value;
                });
              },
              decoration: InputDecoration(
                labelText: "Enter something",
                border: OutlineInputBorder(),
              ),
            ),
            SizedBox(height: 20),
            Text("You typed: $inputText"),
          ],
        ),
      ),
      floatingActionButton: FloatingActionButton(
        onPressed: _incrementCounter,
        tooltip: 'Increment',
        child: const Icon(Icons.add),
      ),
    );
  }
}
```

